

async function resizeImage(base64, maxWidth, maxHeight, outputType = 'jpeg', quality = 0.7) {
    return new Promise(resolve => {
        const img = new Image();
        img.onload = () => {
            let ratio = Math.min(maxWidth / img.width, maxHeight / img.height, 1);
            const canvas = document.createElement('canvas');
            canvas.width = img.width * ratio;
            canvas.height = img.height * ratio;
            const ctx = canvas.getContext('2d');
            
            if(outputType === 'jpeg') {
                // Rellenar fondo blanco solo para JPEG para evitar fondo negro
                ctx.fillStyle = '#FFFFFF';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            }
            
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            
            if(outputType === 'jpeg') {
                resolve(canvas.toDataURL('image/jpeg', quality));
            } else {
                resolve(canvas.toDataURL('image/png')); // PNG no tiene calidad param
            }
        };
        img.src = base64;
    });
}


// ================= GENERAR CERTIFICADO EN ZIP =================

document.addEventListener("DOMContentLoaded", function (){

    const input = document.getElementById("inputPatentes");
    const boton = document.getElementById("btnCertificado");

    boton.addEventListener("click", async () => {
        boton.disabled = true;

        const filtro2Value = document.getElementById("filtro2").value.trim();
        const textareaValue = input.value.trim();

        // Separar por líneas si hay contenido en textarea
        let patentes = [];
        if (textareaValue) {
            patentes = textareaValue.split(/\r?\n/).map(p => p.trim()).filter(p => p);
        }

        // Agregar la patente individual si existe
        if (filtro2Value) {
            patentes.push(filtro2Value);
        }

        if (patentes.length === 0) {
            mostrarAlerta("No hay patentes para generar","warning");
            boton.disabled = false;
            return;
        }

        // Inicializar ZIP
        const zip = new JSZip();
        let errores = [];

        for (let i = 0; i < patentes.length; i++) {
            const patenteActual = patentes[i];

            // Contador en el botón
            boton.innerText = `Generando ${i + 1} de ${patentes.length}...`;

            try {
                // Generamos PDF como Blob
                const pdfBlob = await generarCertificado(patenteActual, true); // true = retornar Blob
                if(pdfBlob)
                    {
                        zip.file(`Certificado_${patenteActual}.pdf`, pdfBlob);
                    }
                else
                {
                    console.warn(`No se generó certificado para ${patenteActual}`);
                    errores.push(patenteActual);
                }

                
            } catch (error) {
                console.error(`Error con patente ${patenteActual}`, error);
            }
        }

        // Descargar ZIP
        if (Object.keys(zip.files).length > 0)
        {
                zip.generateAsync({ type: "blob" }).then(function(content) {
                const a = document.createElement('a');
                a.href = URL.createObjectURL(content);
                a.download = "Certificados.zip";
                a.click();
            });
            mostrarAlerta("Certificados generados correctamente", "success");
            document.getElementById("inputPatentes").value = "";
            document.getElementById("filtro2").value = "";
        }
        else 
        {
            mostrarAlerta("No se generó ningún certificado válido", "warning");
        }


        if (errores.length > 0) 
            {
                mostrarAlerta("No se generaron certificados para las siguientes unidades:<ul><li>" + errores.join("</li><li>") + "</li></ul>", "error");
            }
        boton.disabled = false;
        boton.innerText = "Generar Certificado";
    });



});
// ================= FUNCIÓN GENERAR CERTIFICADO =================

async function generarCertificado(ppu, retornarBlob = false) {

    const { jsPDF } = window.jspdf;
    const patente = document.getElementById("filtro2").value;
    let patenteFinal;

    if(ppu) {
        patenteFinal = validarPatente(ppu);
    } else {
        patenteFinal = validarPatente(patente);
    }

    if(patenteFinal) {
        try {
            const res = await fetch('http://127.0.0.1:5000/certificado', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ session_id, database, patenteFinal })
            });

            const response = await res.json();

            if (!response.data || response.data.length === 0) {
                console.warn("No hay datos para esta patente:", patenteFinal);
                return null;
            }

            const data = response.data[0];
            const vehiculo = {
                razon: 'MITTA S.A',
                rut: data.rut || 'Sin Rut',
                patente: data.patente || '',
                gps: data.imei || '',
                modelogps: data.modelo || 'GPS EXTERNO',
                reporte: data.ult_repo || 'Sin información',
                equip: data.equip || 'Sin registro',
                integracion: data.integracion || 'Sin integración'
            };

            const doc = new jsPDF('p', 'mm', 'a4');

            // ================= FONDO =================
            doc.setFillColor(58, 125, 184);
            doc.rect(0, 0, 210, 35, 'F');

            doc.setFillColor(255, 255, 255);
            doc.setDrawColor(58, 125, 184);
            doc.setLineWidth(1.2);
            doc.roundedRect(10, 15, 190, 270, 10, 10, 'FD');
            doc.setLineWidth(0.2);

            // ================= LOGO =================
            let logoBase64 = "data:image/png;base64,";     
            logoBase64 = await resizeImage(logoBase64, 200, 100,'png');  // ancho/alto máximo en px       
            const imgProps = doc.getImageProperties(logoBase64);

            const imgWidth = 40;
            const imgHeight = (imgProps.height * imgWidth) / imgProps.width;

            doc.addImage(logoBase64, 'JPEG', 20, 20, imgWidth, imgHeight);

            // ================= HEADER =================
            doc.setFont("helvetica", "bold");
            doc.setFontSize(18);
            doc.setTextColor(0, 0, 0);
            doc.text("Certificado", 190, 25, { align: "right" });

            doc.setFontSize(11);
            doc.setTextColor(47, 93, 138);
            doc.text("Instalación Equipos GPS", 190, 31, { align: "right" });

            doc.setTextColor(0, 0, 0);

            // ================= TEXTO =================
            doc.setFont("helvetica", "normal");
            doc.setFontSize(10);

            doc.text("Por medio del presente documento, ", 25, 60);
            doc.setFont("helvetica", "bold");
            doc.text("MIGPS SPA RUT 76.272.389-1", 81, 60);
            doc.setFont("helvetica", "normal");
            doc.text(" certifica que el cliente cuenta con", 130, 60);
            doc.setFont("helvetica", "bold");
            doc.text("solución GPS,", 25, 66);
            doc.setFont("helvetica", "normal");
            doc.text("implementado en el siguiente móvil:", 50, 66);

            // ================= BLOQUES =================
            let y = 70;
            const blockWidth = 160;
            const startX = (210 - blockWidth) / 2;

            const drawBlock = (label, value) => {
                const padding = 5;
                const lineHeight = 5;
                const maxTextWidth = blockWidth - 80;
                const valueLines = doc.splitTextToSize(value, maxTextWidth);
                const labelLines = doc.splitTextToSize(label, 60);
                const lines = Math.max(valueLines.length, labelLines.length);
                const blockHeight = padding + (lines * lineHeight);

                doc.setFillColor(240, 242, 245);
                doc.roundedRect(startX, y, blockWidth, blockHeight, 5, 5, 'F');

                doc.setFont("helvetica", "bold");
                doc.setFontSize(10);
                doc.setTextColor(90, 90, 90);
                doc.text(labelLines, startX + 10, y + 5);

                doc.setFont("helvetica", "normal");
                doc.setTextColor(47, 93, 138);
                doc.text(valueLines, startX + blockWidth - 10, y + 5, { align: "right" });

                y += blockHeight + 3;
            };

            drawBlock("RAZÓN SOCIAL", vehiculo.razon);
            drawBlock("RUT", vehiculo.rut);
            drawBlock("PATENTE", vehiculo.patente);
            drawBlock("GPS", vehiculo.gps);
            drawBlock("MODELO GPS", vehiculo.modelogps);
            drawBlock("FECHA ÚLTIMO REPORTE", vehiculo.reporte);
            drawBlock("EQUIPAMIENTO", vehiculo.equip.toUpperCase());
            drawBlock("INTEGRACIÓN", vehiculo.integracion.toUpperCase());

            // ================= TEXTO FINAL =================
            doc.setFontSize(10);
            doc.setTextColor(0, 0, 0);
            y += 5;
            doc.text(
                "Se extiende el presente certificado a petición de nuestro cliente para los fines que estime conveniente.",
                25,
                y,
                { maxWidth: 160 }
            );

            const hoy = new Date();
            const vencimiento = new Date();
            vencimiento.setMonth(vencimiento.getMonth() + 6); // aqui puedo bajar o aumentar los meses de durabilidad
            const fechaVencimiento = vencimiento.toLocaleDateString('es-CL');

            doc.setFont("helvetica", "bold");
            doc.text("Certificado válido hasta el " + fechaVencimiento, 25, y + 8);

            // ================= FIRMA =================
            y += 20;
            let firmaBase64 = "data:image/png;base64,";
            firmaBase64 = await resizeImage(firmaBase64, 300, 150,'png'); // ancho/alto máximo en px
            doc.addImage(firmaBase64, 'JPEG', 90, y, 30, 35);

            doc.setFont("helvetica", "normal");
            doc.setFontSize(9);
            doc.setTextColor(80, 80, 80);
            doc.text("Soporte y Servicio al Cliente", 105, y + 34, { align: "center" });

            doc.setFont("helvetica", "bold");
            doc.text("MIGPS SPA", 105, y + 37, { align: "center" });

            // ================= FOOTER =================
            const alinFoter = 17;
            const yFooter = 267;

            doc.setFontSize(8);
            let aa = alinFoter;

            doc.setFont("helvetica", "normal");
            let text1 = "Por favor valide la existencia o vigencia del presente móvil llamando al número ";
            doc.text(text1, aa, yFooter);
            aa += doc.getTextWidth(text1);

            doc.setFont("helvetica", "bold");
            let text2 = " 600 600 6404 ";
            doc.text(text2, aa, yFooter);
            aa += doc.getTextWidth(text2);

            doc.setFont("helvetica", "normal");
            let text3 = "o escriba a ";
            doc.text(text3, aa, yFooter);
            aa += doc.getTextWidth(text3);

            doc.setFont("helvetica", "bold");
            doc.text("sacsalfa@wisetrackcorp.com", aa, yFooter);

            const fechaStr = hoy.toLocaleDateString('es-CL');
            const textoFooter = fechaStr + " - Marchant Pereira 201, piso 9 y 10, Providencia, Santiago";

            const containerX = 10;
            const containerWidth = 190;
            const safeWidth = 170;

            let textWidth = doc.getTextWidth(textoFooter);
            let scale = 1;

            if (textWidth > safeWidth) {
                scale = safeWidth / textWidth;
            }

            doc.setFontSize(8 * scale);
            textWidth = doc.getTextWidth(textoFooter);
            const x = containerX + (containerWidth - textWidth) / 2;

            doc.setTextColor(47, 93, 138);
            doc.setFont("helvetica", "bold");
            doc.text(textoFooter, x, 275);

            // ================= DESCARGA =================
            if (retornarBlob) {
                return doc.output('blob'); // para ZIP
            } else {
                doc.save("Certificado_" + vehiculo.patente + ".pdf");
            }

        } catch (error) {
             console.error(error);
             return null; 
        }
    } else {
        const error = "La patente ingresada es incorrecta";
        console.error(error);
        // mostrarAlerta("No se Puede generar certificado!!","error");
    }
}